-- الدفعة الأولى من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft')
-- تحت "الجنايات والقضاء" (jinayat-qada) — تستنفد العنقود بالكامل
-- (10 تصنيفات فرعية من أصل 10، كلها بلا محتوى): الجنايات، الديات،
-- الحدود، التعزير، القضاء والبينات، السياسة الشرعية، الدعوى، البينات
-- والإثبات، الإقرار، الشهادات.
-- كل تصنيف يحصل على درس واحد حقيقي (lessons + lesson_sections +
-- lesson_citations)، مبني على مصادر معتمدة مسمّاة: المغني لابن قدامة،
-- الفقه الإسلامي وأدلته للزحيلي، الطرق الحكمية لابن القيم، أدب القاضي
-- لابن أبي الدم، بداية المجتهد لابن رشد.
-- كل آية استُشهد بها (النساء:93، النساء:92، المائدة:38، النساء:59،
-- ص:26، النساء:58، النساء:105، البقرة:282، النساء:135، الطلاق:2)
-- تحقَّقت حرفياً من artifacts/majalis/public/data/quran محلياً عبر
-- حقل numberInSurah قبل الإدراج.
-- كل حديث مستشهَد به (10 أحاديث) متحقَّق حرفياً عبر WebSearch قبل
-- الإدراج: «لا يحل دم امرئ مسلم... إلا بإحدى ثلاث» (البخاري 6878، ابن
-- مسعود)، حديث كتاب عمرو بن حزم في الديات (رواه النسائي، تلقته الأمة
-- بالقبول)، «لو أن فاطمة بنت محمد سرقت لقطعت يدها» (متفق عليه، عائشة/
-- عروة)، «لا يجلد أحد فوق عشرة أسواط إلا في حد من حدود الله» (متفق
-- عليه، أبو بردة بن نيار)، «إنما أنا بشر وإنكم تختصمون إلي...» (متفق
-- عليه، أم سلمة)، «كلكم راع وكلكم مسؤول عن رعيته» (متفق عليه، ابن
-- عمر)، «لو يعطى الناس بدعواهم لادعى رجال أموال قوم ودماءهم، لكن
-- البينة على المدعي واليمين على من أنكر» (الحديث الثالث والثلاثون من
-- الأربعين النووية، رواه البيهقي بإسناد صحيح وأصل معناه في الصحيحين)،
-- قصة اعتراف ماعز بن مالك بالزنى وأمر النبي «اذهبوا به فارجموه» (متفق
-- عليه)، «ألا أنبئكم بأكبر الكبائر؟... وشهادة الزور» (متفق عليه، أبو
-- بكرة).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات العشرة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) الجنايات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='9e44df86-f00f-4996-a85e-2291cfec0ab4' AND title='تعريف الجناية وأقسامها باعتبار القصد') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف الجناية وأقسامها باعتبار القصد', 'معنى الجناية في الفقه الإسلامي وتقسيمها إلى عمد وشبه عمد وخطأ، وحرمة الدم المسلم إلا بحق', '9e44df86-f00f-4996-a85e-2291cfec0ab4', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وأقسامها', 'الجناية في اصطلاح الفقهاء: كل فعل محرم شرعاً يقع على النفس أو ما دونها بالقتل أو الجرح أو الضرب. وتنقسم باعتبار القصد إلى ثلاثة أقسام: عمد (قصد الفعل والقتل معاً بآلة تقتل غالباً)، وشبه عمد (قصد الفعل دون القتل)، وخطأ (لا قصد فيه إلى الفعل ولا إلى القتل)، ولكل قسم حكمه الخاص في العقوبة والدية والكفارة.', 1),
    (v_lesson, 'evidence', 'حرمة الدم وأصل التغليظ في القتل العمد', 'قال تعالى: ﴿وَمَن يَقْتُلْ مُؤْمِنًا مُّتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ خَالِدًا فِيهَا وَغَضِبَ اللَّهُ عَلَيْهِ وَلَعَنَهُ وَأَعَدَّ لَهُ عَذَابًا عَظِيمًا﴾ (النساء: 93)، وعن عبد الله بن مسعود رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ، يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ، إِلَّا بِإِحْدَى ثَلَاثٍ: النَّفْسُ بِالنَّفْسِ، وَالثَّيِّبُ الزَّانِي، وَالْمَارِقُ مِنَ الدِّينِ التَّارِكُ لِلْجَمَاعَةِ» متفق عليه، فحصر الحديث الحالات التي يباح فيها دم المسلم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المغني — الإمام موفق الدين ابن قدامة المقدسي (كتاب الجنايات)', 1);
  END IF;

  -- 2) الديات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='ffef970f-4936-49be-94b0-5e67e24795cd' AND title='تعريف الدية وأصل تقديرها بمائة من الإبل') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف الدية وأصل تقديرها بمائة من الإبل', 'معنى الدية ومتى تجب بدلاً عن القصاص، وأصل تقدير دية النفس بمائة من الإبل من كتاب النبي لعمرو بن حزم', 'ffef970f-4936-49be-94b0-5e67e24795cd', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها ومتى تجب', 'الدية: المال الواجب بالجناية على النفس أو ما دونها، تجب في القتل الخطأ وشبه العمد بدلاً محتّماً، وفي القتل العمد إذا عفا أولياء الدم عن القصاص إلى الدية أو الصلح. وقد فصّل الفقهاء مقاديرها في النفس وما دونها من الأعضاء والمنافع اعتماداً على كتاب النبي صلى الله عليه وسلم المشهور المتلقّى بالقبول لعمرو بن حزم.', 1),
    (v_lesson, 'evidence', 'أصلها القرآني ومقدارها في السنة', 'قال تعالى: ﴿وَمَا كَانَ لِمُؤْمِنٍ أَن يَقْتُلَ مُؤْمِنًا إِلَّا خَطَأً وَمَن قَتَلَ مُؤْمِنًا خَطَأً فَتَحْرِيرُ رَقَبَةٍ مُّؤْمِنَةٍ وَدِيَةٌ مُّسَلَّمَةٌ إِلَىٰ أَهْلِهِ﴾ (النساء: 92)، وفي كتاب النبي صلى الله عليه وسلم لعمرو بن حزم رواه النسائي وتلقّته الأمة بالقبول: «وَإِنَّ فِي النَّفْسِ الدِّيَةَ مِائَةً مِنَ الْإِبِلِ»، وهذا أصل تقدير دية النفس المؤمنة عند جمهور الفقهاء.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الفقه الإسلامي وأدلته — الدكتور وهبة الزحيلي (كتاب الديات)', 1);
  END IF;

  -- 3) الحدود
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='cdddf44d-4c03-4c3f-9e98-4da6060d0706' AND title='تعريف الحدود وخصيصة عدم قبول الشفاعة فيها') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف الحدود وخصيصة عدم قبول الشفاعة فيها', 'معنى الحد في الفقه الإسلامي وخصائصه، وموقف النبي صلى الله عليه وسلم الحازم من الشفاعة في الحدود', 'cdddf44d-4c03-4c3f-9e98-4da6060d0706', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وخصائصها', 'الحد في اصطلاح الفقهاء: عقوبة مقدَّرة شرعاً واجبة حقاً لله تعالى، كحد السرقة والزنى وشرب الخمر والقذف والحرابة. وتتميز الحدود عن غيرها من العقوبات بأنها مقدَّرة لا تُنقص ولا تُزاد، ولا تسقط بالعفو أو الشفاعة إذا بلغت السلطان، درءاً للفوضى وصوناً لحرمات الله.', 1),
    (v_lesson, 'evidence', 'أصل حد السرقة والنهي عن الشفاعة فيه', 'قال تعالى: ﴿وَالسَّارِقُ وَالسَّارِقَةُ فَاقْطَعُوا أَيْدِيَهُمَا جَزَاءً بِمَا كَسَبَا نَكَالًا مِّنَ اللَّهِ﴾ (المائدة: 38)، ولما شُفع للنبي صلى الله عليه وسلم في امرأة سرقت، غضب وقال: «أَتَشْفَعُ فِي حَدٍّ مِنْ حُدُودِ اللَّهِ؟» ثم قال: «وَالَّذِي نَفْسِي بِيَدِهِ، لَوْ أَنَّ فَاطِمَةَ بِنْتَ مُحَمَّدٍ سَرَقَتْ لَقَطَعْتُ يَدَهَا» متفق عليه، فبيّن هذا أن الحدود لا تفرّق بين شريف ووضيع.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الفقه الإسلامي وأدلته — الدكتور وهبة الزحيلي (كتاب الحدود)', 1);
  END IF;

  -- 4) التعزير
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='4f68cd28-fef3-435b-a547-ae5856b86f5a' AND title='تعريف التعزير وضابط الحد الأقصى للتأديب') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف التعزير وضابط الحد الأقصى للتأديب', 'معنى التعزير وكونه مفوَّضاً لاجتهاد الحاكم فيما لا حد فيه مقدَّر، وضابط النبي في عدم تجاوز عشرة أسواط في غير حدود الله', '4f68cd28-fef3-435b-a547-ae5856b86f5a', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه ومرجعيته', 'التعزير: عقوبة تأديبية غير مقدَّرة شرعاً تجب في كل معصية ليس فيها حد مقدَّر ولا كفارة، يفوَّض تقديرها نوعاً ومقداراً إلى اجتهاد ولي الأمر أو القاضي بحسب حال الجاني والجريمة وأثرها، وذلك تحت مرجعية طاعة أولي الأمر فيما لا معصية فيه وردّ التنازع إلى الله ورسوله.', 1),
    (v_lesson, 'evidence', 'أصل التفويض وضابط التأديب', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا أَطِيعُوا اللَّهَ وَأَطِيعُوا الرَّسُولَ وَأُولِي الْأَمْرِ مِنكُمْ فَإِن تَنَازَعْتُمْ فِي شَيْءٍ فَرُدُّوهُ إِلَى اللَّهِ وَالرَّسُولِ﴾ (النساء: 59)، وعن أبي بردة الأنصاري رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «لَا يُجْلَدُ أَحَدٌ فَوْقَ عَشَرَةِ أَسْوَاطٍ، إِلَّا فِي حَدٍّ مِنْ حُدُودِ اللَّهِ» متفق عليه، وهذا أصل الفارق بين عقوبة التعزير التأديبية وعقوبة الحد المقدَّرة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'بداية المجتهد ونهاية المقتصد — القاضي أبو الوليد ابن رشد', 1);
  END IF;

  -- 5) القضاء والبينات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='ebf1944a-9526-4a4f-a88b-516d11c0e645' AND title='مشروعية القضاء وأصل الحكم بالظاهر من البينات') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مشروعية القضاء وأصل الحكم بالظاهر من البينات', 'معنى القضاء ومشروعيته، وبيان أن حكم القاضي مبني على الظاهر من البينات لا على باطن الأمر', 'ebf1944a-9526-4a4f-a88b-516d11c0e645', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه ومكانته', 'القضاء: فصل الخصومات بين الناس بحكم شرعي على وجه الإلزام. وهو فرض كفاية من فروض الدين التي لا يستقيم أمر الناس بدونها، أوجبه الشارع لحفظ الحقوق ورفع الظلم، ويجب أن يقوم به من تتوفر فيه أهلية الاجتهاد والعدالة والعلم بأحكام الشريعة.', 1),
    (v_lesson, 'evidence', 'أصل مشروعيته وحكمه بالظاهر', 'قال تعالى مخاطباً داود عليه السلام: ﴿يَا دَاوُودُ إِنَّا جَعَلْنَاكَ خَلِيفَةً فِي الْأَرْضِ فَاحْكُم بَيْنَ النَّاسِ بِالْحَقِّ وَلَا تَتَّبِعِ الْهَوَىٰ﴾ (ص: 26)، وعن أم سلمة رضي الله عنها أن رسول الله صلى الله عليه وسلم قال: «إِنَّمَا أَنَا بَشَرٌ، وَإِنَّكُمْ تَخْتَصِمُونَ إِلَيَّ، وَلَعَلَّ بَعْضَكُمْ أَنْ يَكُونَ أَلْحَنَ بِحُجَّتِهِ مِنْ بَعْضٍ، فَأَقْضِيَ لَهُ عَلَى نَحْوِ مَا أَسْمَعُ» متفق عليه، فبيّن أن قضاء القاضي إنما هو حكم بالظاهر لا يُحلّ حراماً ولا يُحرّم حلالاً في نفس الأمر.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أدب القاضي — الإمام أبو إسحاق إبراهيم بن أبي الدم', 1);
  END IF;

  -- 6) السياسة الشرعية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='188dcd44-bd29-4a13-a0bc-f53c55569af0' AND title='تعريف السياسة الشرعية ومسؤولية الراعي عن رعيته') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف السياسة الشرعية ومسؤولية الراعي عن رعيته', 'معنى السياسة الشرعية وضابط ارتباطها بتحقيق العدل، ومسؤولية كل راعٍ عن رعيته في الإسلام', '188dcd44-bd29-4a13-a0bc-f53c55569af0', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وضابطها', 'السياسة الشرعية: تدبير شؤون الأمة وإدارة أمورها العامة بما يحقق مصالحها ويدرأ عنها المفاسد، في حدود ما لا يخالف نصاً شرعياً قطعياً. عرّفها ابن عقيل بأنها ما كان فعلاً يكون معه الناس أقرب إلى الصلاح وأبعد عن الفساد وإن لم يشرعه رسول الله ولا نزل به وحي، وضابطها عند العلماء أنها لا تخرج عن العدل الذي هو مقصود الشريعة الأعظم.', 1),
    (v_lesson, 'evidence', 'أصل العدل في الحكم ومسؤولية الراعي', 'قال تعالى: ﴿إِنَّ اللَّهَ يَأْمُرُكُمْ أَن تُؤَدُّوا الْأَمَانَاتِ إِلَىٰ أَهْلِهَا وَإِذَا حَكَمْتُم بَيْنَ النَّاسِ أَن تَحْكُمُوا بِالْعَدْلِ﴾ (النساء: 58)، وعن عبد الله بن عمر رضي الله عنهما أن رسول الله صلى الله عليه وسلم قال: «أَلَا كُلُّكُمْ رَاعٍ، وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِ، فَالْأَمِيرُ الَّذِي عَلَى النَّاسِ رَاعٍ وَهُوَ مَسْئُولٌ عَنْ رَعِيَّتِهِ» متفق عليه، فربط هذا الحديث ولاية الأمر بالمسؤولية أمام الله عن رعاية العدل فيها.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الطرق الحكمية في السياسة الشرعية — الإمام ابن قيم الجوزية', 1);
  END IF;

  -- 7) الدعوى
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='ae0e62a5-2e0d-49a9-94aa-c0ffcf18064c' AND title='تعريف الدعوى وأركانها الثلاثة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف الدعوى وأركانها الثلاثة', 'معنى الدعوى القضائية وأركانها من مدعٍ ومدعى عليه ومدعى به، وأصل الأمر بالحكم بين الناس بالحق', 'ae0e62a5-2e0d-49a9-94aa-c0ffcf18064c', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وأركانها', 'الدعوى في اصطلاح الفقهاء: إخبار عن وجوب حق على الغير عند حاكم يملك إلزامه به. ولها أركان ثلاثة لا تقوم إلا بها: مدَّعٍ (وهو من يطالب بحق ليس في يده)، ومدَّعى عليه (وهو من يُطالَب)، ومدَّعى به (وهو الحق المطلوب)، ولا تُسمع الدعوى عند القضاة إلا مستوفية لهذه الأركان محددة المقدار والوصف.', 1),
    (v_lesson, 'evidence', 'أصل الحكم بالحق في الخصومات', 'قال تعالى: ﴿إِنَّا أَنزَلْنَا إِلَيْكَ الْكِتَابَ بِالْحَقِّ لِتَحْكُمَ بَيْنَ النَّاسِ بِمَا أَرَاكَ اللَّهُ وَلَا تَكُن لِّلْخَائِنِينَ خَصِيمًا﴾ (النساء: 105)، وهذه الآية أصل في وجوب حكم القاضي بين المتخاصمين بالحق الذي يظهر له من الدعوى وبيّناتها، وعدم الانحياز لأحد طرفيها بغير حق.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أدب القاضي — الإمام أبو إسحاق إبراهيم بن أبي الدم', 1);
  END IF;

  -- 8) البينات والإثبات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='6360b7b7-debe-4f43-b13c-c3cb4805916a' AND title='طرق الإثبات في القضاء وقاعدة البينة واليمين') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('طرق الإثبات في القضاء وقاعدة البينة واليمين', 'أهم طرق الإثبات الشرعية من كتابة وشهادة ويمين، والقاعدة النبوية في توزيع عبء الإثبات بين المدعي والمدعى عليه', '6360b7b7-debe-4f43-b13c-c3cb4805916a', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه وأهم طرقه', 'الإثبات: إقامة الدليل أمام القضاء على حق متنازَع فيه بالطرق التي اعتبرها الشرع، وأهمها: الإقرار، والشهادة، واليمين، والقرائن، والكتابة والتوثيق. وقد أرشد القرآن إلى توثيق الديون بالكتابة والإشهاد صوناً للحقوق من الجحود والنزاع.', 1),
    (v_lesson, 'evidence', 'أصل التوثيق وقاعدة توزيع عبء الإثبات', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا تَدَايَنتُم بِدَيْنٍ إِلَىٰ أَجَلٍ مُّسَمًّى فَاكْتُبُوهُ ۚ وَاسْتَشْهِدُوا شَهِيدَيْنِ مِن رِّجَالِكُمْ﴾ (البقرة: 282)، وعن ابن عباس رضي الله عنهما أن رسول الله صلى الله عليه وسلم قال: «لَوْ يُعْطَى النَّاسُ بِدَعْوَاهُمْ لَادَّعَى رِجَالٌ أَمْوَالَ قَوْمٍ وَدِمَاءَهُمْ، وَلَكِنَّ الْبَيِّنَةَ عَلَى الْمُدَّعِي وَالْيَمِينَ عَلَى مَنْ أَنْكَرَ»، وهو الحديث الثالث والثلاثون من الأربعين النووية، رواه البيهقي بإسناد صحيح وأصل معناه ثابت في الصحيحين، وهو قاعدة كبرى في توزيع عبء الإثبات.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الطرق الحكمية في السياسة الشرعية — الإمام ابن قيم الجوزية', 1);
  END IF;

  -- 9) الإقرار
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='5d823caa-4561-4a56-8f04-e9b30e1391fb' AND title='تعريف الإقرار وكونه أقوى طرق الإثبات') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف الإقرار وكونه أقوى طرق الإثبات', 'معنى الإقرار وحجيته الملزمة على المقرّ، وقصة اعتراف ماعز بن مالك التي بُني عليها فقه شروط الإقرار', '5d823caa-4561-4a56-8f04-e9b30e1391fb', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه وحجيته', 'الإقرار: إخبار المرء عن حق عليه لغيره بصيغة تدل على الإلزام. وهو أقوى طرق الإثبات وأقطعها للنزاع، لأن العاقل لا يُتَّهم في الشهادة على نفسه بما يضرها، فيُلزم به المقرّ ولو أدّى إلى إقامة حد عليه، بشرط أن يكون بالغاً عاقلاً مختاراً غير مكرَه.', 1),
    (v_lesson, 'evidence', 'أصل الشهادة على النفس وقصة إقرار ماعز', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا كُونُوا قَوَّامِينَ بِالْقِسْطِ شُهَدَاءَ لِلَّهِ وَلَوْ عَلَىٰ أَنفُسِكُمْ﴾ (النساء: 135)، وقد جاء ماعز بن مالك رضي الله عنه إلى النبي صلى الله عليه وسلم فأقرّ على نفسه بالزنى أربع مرات، فسأله النبي عن عقله وإحصانه، فلما ثبت إقراره قال صلى الله عليه وسلم: «اذْهَبُوا بِهِ فَارْجُمُوهُ» متفق عليه، فبنى الفقهاء على هذه القصة اشتراط تكرار الإقرار واستفصال القاضي قبل تنفيذ الحد.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المغني — الإمام موفق الدين ابن قدامة المقدسي (كتاب الإقرار)', 1);
  END IF;

  -- 10) الشهادات
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='a9df0d70-0d52-404f-903f-d1e0b0d326af' AND title='تعريف الشهادة وشروط قبولها وخطورة شهادة الزور') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف الشهادة وشروط قبولها وخطورة شهادة الزور', 'معنى الشهادة وشرط العدالة في الشاهد، وتحذير النبي صلى الله عليه وسلم البالغ من شهادة الزور', 'a9df0d70-0d52-404f-903f-d1e0b0d326af', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وشروطها', 'الشهادة: إخبار صادق أمام القضاء بحق للغير على وجه يوجب الحكم به. ويشترط في الشاهد شروط منها: العقل والبلوغ والإسلام والعدالة (وهي استقامة الدين واجتناب الكبائر)، والحفظ وعدم التهمة، وقد أمر الشرع بإقامة الشهادة وعدم كتمانها لأنها حفظ للحقوق بين الناس.', 1),
    (v_lesson, 'evidence', 'أصل الإشهاد وتحريم شهادة الزور', 'قال تعالى: ﴿فَإِذَا بَلَغْنَ أَجَلَهُنَّ فَأَمْسِكُوهُنَّ بِمَعْرُوفٍ أَوْ فَارِقُوهُنَّ بِمَعْرُوفٍ وَأَشْهِدُوا ذَوَيْ عَدْلٍ مِّنكُمْ وَأَقِيمُوا الشَّهَادَةَ لِلَّهِ﴾ (الطلاق: 2)، وعن أبي بكرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «أَلَا أُنَبِّئُكُمْ بِأَكْبَرِ الْكَبَائِرِ؟» ثلاثاً، قالوا: بلى يا رسول الله، قال: «الْإِشْرَاكُ بِاللَّهِ، وَعُقُوقُ الْوَالِدَيْنِ»، وكان متكئاً فجلس وقال: «أَلَا وَقَوْلُ الزُّورِ، وَشَهَادَةُ الزُّورِ» متفق عليه، فقرن شهادة الزور بأكبر الكبائر تحذيراً من عظم خطرها.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'بداية المجتهد ونهاية المقتصد — القاضي أبو الوليد ابن رشد (كتاب الشهادات)', 1);
  END IF;

